/**
 * This is a compatibility layer that forwards to the new internal implementation.
 * This file is the main entry point for older versions of the module or for direct imports.
 */

/**
 * Detect Electron renderer / nwjs process, which is node, but we should
 * treat as a browser.
 */
if (typeof process === 'undefined' || process.type === 'renderer' || process.browser === true || process.__nwjs) {
  module.exports = require('./src/browser.js');
} else {
  /**
   * If we're in Node.js, use the Node.js-specific implementation
   */
  module.exports = require('./src/node.js');
}